using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var notes = new ResearchNotes();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            Console.WriteLine($"  [Tool] Searching web for: \"{query}\"");
            return WebSearchSimulator.SearchAsync(query);
        },
        "search_web",
        "Searches the web for information on a given query. Returns a list of relevant snippets."),

    AIFunctionFactory.Create(
        ([Description("A concise note to save for later reference")] string note,
         [Description("Category or topic label for the note")] string category) =>
        {
            notes.Add(category, note);
            Console.WriteLine($"  [Tool] Note saved under \"{category}\"");
            return $"Note saved under category '{category}'.";
        },
        "take_note",
        "Saves a research note under a given category for later summarization."),

    AIFunctionFactory.Create(
        () =>
        {
            var allNotes = notes.GetAll();
            Console.WriteLine("  [Tool] Retrieving all saved notes");
            return allNotes;
        },
        "get_notes",
        "Retrieves all previously saved research notes organized by category."),
};

// --- Agent setup ---
const string instructions = """
    You are a research agent. Your goal is to thoroughly research a topic provided by the user.

    Follow this process:
    1. Break the topic into 2-3 key sub-questions.
    2. Use the search_web tool to find information for each sub-question.
    3. Use the take_note tool to save important findings with appropriate categories.
    4. After gathering enough information, use get_notes to review your findings.
    5. Provide a well-structured summary with key points and cite your sources.

    Be thorough but concise. Always save notes before summarizing.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: \"{topic}\"");
Console.WriteLine(new string('─', 50));

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session: null,
    options: runOptions);

Console.WriteLine();
Console.WriteLine(new string('═', 50));
Console.WriteLine("RESEARCH SUMMARY");
Console.WriteLine(new string('═', 50));
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine();
    Console.WriteLine($"[Tokens used — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}]");
}

// --- Supporting types ---

/// <summary>
/// In-memory storage for research notes organized by category.
/// </summary>
sealed class ResearchNotes
{
    private readonly Dictionary<string, List<string>> _notes = [];

    public void Add(string category, string note)
    {
        if (!_notes.TryGetValue(category, out var list))
        {
            list = [];
            _notes[category] = list;
        }

        list.Add(note);
    }

    public Dictionary<string, List<string>> GetAll() => _notes;
}

/// <summary>
/// Simulates web search results for demonstration purposes.
/// Replace with a real search API (e.g., Bing Search API) in production.
/// </summary>
static class WebSearchSimulator
{
    public static Task<string[]> SearchAsync(string query)
    {
        // Simulated search results based on query keywords
        var results = new List<string>
        {
            $"[Result 1] According to recent studies on '{query}': " +
            "This topic has seen significant developments in the past year, " +
            "with multiple research groups publishing findings.",

            $"[Result 2] A comprehensive review of '{query}' notes that " +
            "experts generally agree on the core principles, though debate " +
            "continues on specific implementation approaches.",

            $"[Result 3] Industry analysis of '{query}' shows growing adoption " +
            "across sectors, with particular momentum in technology and healthcare.",
        };

        return Task.FromResult(results.ToArray());
    }
}

